4354 // Replaces (switch (select cond, X, C)/(select cond, C, X)) with (switch X) if
4355 // we can prove that both (switch C) and (switch X) go to the default when cond
4356 // is false/true.
4357 static Value *simplifySwitchOnSelectUsingRanges(SwitchInst &SI,
4358                                                 SelectInst *Select,
4359                                                 bool IsTrueArm) {
4360   unsigned CstOpIdx = IsTrueArm ? 1 : 2;
4361   auto *C = dyn_cast<ConstantInt>(Select->getOperand(CstOpIdx));
4362   if (!C)
4363     return nullptr;
4364 
4365   BasicBlock *CstBB = SI.findCaseValue(C)->getCaseSuccessor();
4366   if (CstBB != SI.getDefaultDest())
4367     return nullptr;
4368   Value *X = Select->getOperand(3 - CstOpIdx);
4369   CmpPredicate Pred;
4370   const APInt *RHSC;
4371   if (!match(Select->getCondition(),
4372              m_ICmp(Pred, m_Specific(X), m_APInt(RHSC))))
4373     return nullptr;
4374   if (IsTrueArm)
4375     Pred = ICmpInst::getInversePredicate(Pred);
4376 
4377   // See whether we can replace the select with X
4378   ConstantRange CR = ConstantRange::makeExactICmpRegion(Pred, *RHSC);
4379   for (auto Case : SI.cases())
4380     if (!CR.contains(Case.getCaseValue()->getValue()))
4381       return nullptr;
4382 
4383   return X;
4384 }
