4392   auto MaybeInvertible = [&](Value *Cond) -> InvertFn {
4393     if (match(Cond, m_Add(m_Value(Op0), m_APInt(CondOpC))))
4394       // Change 'switch (X+C) case Case:' into 'switch (X) case Case-C'.
4395       return [](const APInt &Case, const APInt &C) { return Case - C; };
4396 
4397     if (match(Cond, m_Sub(m_APInt(CondOpC), m_Value(Op0))))
4398       // Change 'switch (C-X) case Case:' into 'switch (X) case C-Case'.
4399       return [](const APInt &Case, const APInt &C) { return C - Case; };
4400 
4401     if (match(Cond, m_Xor(m_Value(Op0), m_APInt(CondOpC))) &&
4402         !CondOpC->isMinSignedValue() && !CondOpC->isMaxSignedValue())
4403       // Change 'switch (X^C) case Case:' into 'switch (X) case Case^C'.
4404       // Prevent creation of large case values by excluding extremes.
4405       return [](const APInt &Case, const APInt &C) { return Case ^ C; };
4406 
4407     return nullptr;
4408   };
