2668 template <typename LHS_t, typename RHS_t, typename Sum_t>
2669 struct UAddWithOverflow_match {
2670   LHS_t L;
2671   RHS_t R;
2672   Sum_t S;
2673 
2674   UAddWithOverflow_match(const LHS_t &L, const RHS_t &R, const Sum_t &S)
