2690 
2691     // a >u (a + b), b >u (a + b)
2692     if (Pred == ICmpInst::ICMP_UGT)
2693       if (AddExpr.match(ICmpRHS) && (ICmpLHS == AddLHS || ICmpLHS == AddRHS))
2694         return L.match(AddLHS) && R.match(AddRHS) && S.match(ICmpRHS);
